import random

def bogo_sort(arr):
    def is_sorted(a):
        for i in range(len(a) - 1):
            if a[i] > a[i+1]: return False
        return True
    while not is_sorted(arr):
        random.shuffle(arr)
    return arr

if __name__ == "__main__":
    print(f"Sorted: {bogo_sort([2, 1])}")
